package com.example.app

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class LoginActivity : AppCompatActivity() {

    private val prefs: SharedPreferences by lazy {
        getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    }

    private val isAuthenticated: Boolean
        get() = prefs.getBoolean(KEY_AUTHENTICATED, false)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (isAuthenticated) {
            goToHome()
            return
        }

        setContentView(R.layout.activity_login)

        val passwordEditText = findViewById<EditText>(R.id.passwordEditText)
        val loginButton = findViewById<Button>(R.id.loginButton)
        val biometricButton = findViewById<Button>(R.id.biometricButton)

        loginButton.setOnClickListener {
            val password = passwordEditText.text?.toString().orEmpty()
            if (isPasswordValid(password)) {
                markAuthenticated()
                goToHome()
            } else {
                Toast.makeText(this, "Invalid password", Toast.LENGTH_SHORT).show()
            }
        }

        biometricButton.setOnClickListener {
            authenticateWithBiometric(passwordEditText)
        }

        if (canUseBiometric()) {
            authenticateWithBiometric(passwordEditText)
        }
    }

    private fun canUseBiometric(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE,
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE,
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> false
            else -> false
        }
    }

    private fun authenticateWithBiometric(passwordEditText: EditText? = null) {
        if (!canUseBiometric()) {
            Toast.makeText(
                this,
                "Biometric not available. Please sign in with your password.",
                Toast.LENGTH_SHORT
            ).show()
            passwordEditText?.requestFocus()
            return
        }

        val executor: Executor = ContextCompat.getMainExecutor(this)
        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Sign in")
            .setSubtitle("Use your fingerprint to continue")
            .setDescription("Authenticate with your fingerprint or use your password instead")
            .setNegativeButtonText("Use password")
            .build()

        val biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    markAuthenticated()
                    Toast.makeText(this@LoginActivity, "Authenticated", Toast.LENGTH_SHORT).show()
                    goToHome()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint not recognized. Try again or use your password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON,
                        BiometricPrompt.ERROR_USER_CANCELED,
                        BiometricPrompt.ERROR_CANCELED -> {
                            Toast.makeText(
                                this@LoginActivity,
                                "Please sign in with your password.",
                                Toast.LENGTH_SHORT
                            ).show()
                            passwordEditText?.requestFocus()
                        }
                        else -> {
                            Toast.makeText(
                                this@LoginActivity,
                                "Biometric error: $errString",
                                Toast.LENGTH_SHORT
                            ).show()
                        }
                    }
                }
            }
        )

        biometricPrompt.authenticate(promptInfo)
    }

    private fun markAuthenticated() {
        prefs.edit().putBoolean(KEY_AUTHENTICATED, true).apply()
    }

    private fun isPasswordValid(password: String): Boolean {
        return password == "password123"
    }

    private fun goToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "authenticated"
    }
}

class HomeActivity : AppCompatActivity() {

    private val prefs: SharedPreferences by lazy {
        getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (!prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        setContentView(R.layout.activity_home)
    }

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "authenticated"
    }
}